module top_module(
    X   ,
    A1  ,
    A2  ,
    B1  ,
    C1  ,
    D1  ,
    VPWR,
    VGND
);output X   ;
    input  A1  ;
    input  A2  ;
    input  B1  ;
    input  C1  ;
    input  D1  ;
    input  VPWR;
    input  VGND;

  wire temp1_A1 & (A2 | B1) = A1 & (A2 | B1);
  wire temp2_(C1 ^ D1) = (C1 ^ D1);
  assign X = temp1_A1 & (A2 | B1) & temp2_(C1 ^ D1);

    // Connect VPWR to power supply and VGND to ground
    assign VPWR = 1'b1;
    assign VGND = 1'b0;

endmodule
